"use client";
import { motion } from "framer-motion";
import React, { useEffect, useRef, useState } from "react";

interface AnimateChangeInHeightProps {
  children: React.ReactNode;
  className?: string;
}

export const AnimateChangeInHeight: React.FC<AnimateChangeInHeightProps> = ({
  children,
  className,
}) => {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const [height, setHeight] = useState<number | "auto">("auto");

  useEffect(() => {
    if (containerRef.current) {
      const resizeObserver = new ResizeObserver((entries) => {
        // We only have one entry, so we can use entries[0].
        const observedHeight = entries[0].contentRect.height;
        setHeight(observedHeight);
      });

      resizeObserver.observe(containerRef.current);

      return () => {
        // Cleanup the observer when the component is unmounted
        resizeObserver.disconnect();
      };
    }
  }, []);

  return (
    <motion.div
      className={className}
      style={{ height }}
      animate={{ height }}
      transition={{ duration: 0.1 }}
    >
      <div ref={containerRef}>{children}</div>
    </motion.div>
  );
};

"use client";
import { useCallback, useEffect, useState } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { ModalVariant } from "./context";

const ModalWrapper = ({
  transitionDurationInMs,
  modal,
  isActive,
  index,
  preventFocusTrap,
}: {
  transitionDurationInMs: number;
  modal: ModalVariant;
  isActive: boolean;
  index: number;
  preventFocusTrap?: boolean;
}) => {
  const [focusTrapHandleTrigger, setFocusTrapHandleTrigger] = useState(0);

  const handleFocusTrap = useCallback(() => {
    const wrapper = document.querySelector(
      "[data-current-modal]"
    ) as HTMLDivElement;

    if (!isActive || !wrapper) return;
    const focusableElements = wrapper.querySelectorAll<HTMLElement>(
      'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
    );
    const firstFocusable = focusableElements[0];
    const lastFocusable = focusableElements[focusableElements.length - 1];

    const handleKeyDown = (e: KeyboardEvent) => {
      if (!isActive) return;
      if (e.key !== "Tab") return;

      // If shift + tab on first element, go to last
      if (e.shiftKey && document.activeElement === firstFocusable) {
        e.preventDefault();
        lastFocusable?.focus();
      }
      // If tab on last element, go to first
      else if (!e.shiftKey && document.activeElement === lastFocusable) {
        e.preventDefault();
        firstFocusable?.focus();
      }
    };

    wrapper.addEventListener("keydown", handleKeyDown);
    if (isActive) firstFocusable?.focus();

    return () => {
      wrapper.removeEventListener("keydown", handleKeyDown);
    };
  }, [isActive]);

  useEffect(() => {
    if (focusTrapHandleTrigger === 0) return;
    return handleFocusTrap();
  }, [focusTrapHandleTrigger, handleFocusTrap]);

  return (
    <AnimatePresence mode="popLayout">
      <motion.div
        onAnimationComplete={() => {
          if (preventFocusTrap) return;
          setTimeout(() => {
            setFocusTrapHandleTrigger(prev => prev + 1);
          }, transitionDurationInMs);
        }}
        key={modal.id + index}
        initial={
          isActive
            ? {
                opacity: 0,
                filter: "blur(10px)",
                x: index === 0 ? 0 : 300,
                scale: index === 0 ? 0.9 : 1,
              }
            : undefined
        }
        animate={
          isActive
            ? {
                opacity: 1,
                filter: "blur(0px)",
                x: 0,
                scale: 1,
              }
            : {
                opacity: 0,
                filter: "blur(10px)",
                x: -300,
              }
        }
        exit={
          isActive ? { opacity: 0, filter: "blur(10px)", x: 300 } : undefined
        }
        transition={{
          duration: transitionDurationInMs / 1000,
        }}
        className={
          isActive
            ? "relative min-h-0 min-w-0"
            : "pointer-events-none absolute inset-0 overflow-hidden"
        }
        aria-hidden={!isActive}
        tabIndex={-1}
      >
        <div data-current-modal={isActive ? "" : undefined}>
          {modal.content}
        </div>
      </motion.div>
    </AnimatePresence>
  );
};

export default ModalWrapper;

"use client";
import { createContext, useContext, useState } from "react";
import { debug } from "@/lib/logger";
import {
  Dialog,
  DialogDescription,
  DialogHeader,
  DialogPlaceholder,
  DialogTitle,
} from "./dialog";
import {
  Drawer,
  DrawerDescription,
  DrawerHeader,
  DrawerPlaceholder,
  DrawerTitle,
} from "./drawer";
import { VisuallyHidden } from "radix-ui";
import { AnimateChangeInHeight } from "./AnimateChangeInHeight";
import useCurrentModalInfo from "./use-current-modal-info";
import ModalWrapper from "./ModalWrapper";
import useMediaQuery from "@/hooks/use-media-query";

const VISIBILITY_TRANSITION_DURATION = 100;
const STACK_UPDATE_TRANSITION_DURATION = 300;
const SMALL_SCREEN_BREAKPOINT = "32rem";

export type ModalVariant = {
  id: string;
  content: React.ReactNode;
  /** Tailwind max-width class for dialog mode (e.g. "max-w-2xl"). Defaults to "max-w-sm". */
  dialogWidth?: string;
};

type ModalMode = "dialog" | "drawer";

type ModalContextType = {
  show: () => Promise<void>;
  hide: () => Promise<void>;
  onVisibilityChange: (open: boolean) => void;
  isOpen: boolean;
  mode: ModalMode | null;
  stack: Array<string>;
  pushModal: (variant: ModalVariant, replaceAll?: boolean) => void;
  popModal: () => void;
  clear: () => void;
};

const ModalContext = createContext<ModalContextType | null>(null);
export const ModalModeContext = createContext<ModalMode | null>(null);

const ModalStack = ({
  mode,
  children,
  isOpen,
  onOpenChange,
  dismissible,
  dialogWidth,
}: {
  mode: ModalMode | null;
  children: React.ReactNode;
  dismissible: boolean;
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  dialogWidth: string;
}) => {
  if (mode === "dialog") {
    debug.log("dismissible", dismissible);
    return (
      <Dialog open={isOpen} onOpenChange={onOpenChange}>
        <DialogPlaceholder
          className="overflow-hidden"
          dialogWidth={dialogWidth}
          onEscapeKeyDown={(e) => {
            e.preventDefault();
            if (dismissible) {
              onOpenChange(false);
            }
          }}
          onInteractOutside={(e) => {
            e.preventDefault();
            if (dismissible) {
              onOpenChange(false);
            }
          }}
        >
          <AnimateChangeInHeight className="relative">
            {children}
          </AnimateChangeInHeight>
        </DialogPlaceholder>
      </Dialog>
    );
  }
  if (mode === "drawer") {
    return (
      <Drawer
        open={isOpen}
        onOpenChange={onOpenChange}
        dismissible={dismissible}
        repositionInputs={false}
      >
        <DrawerPlaceholder dismissible={dismissible}>
          {children}
        </DrawerPlaceholder>
      </Drawer>
    );
  }
  return null;
};

export const ModalProvider = ({ children }: { children: React.ReactNode }) => {
  const [modalIdStack, setModalIdStack] = useState<string[]>([]);
  const [modalStack, setModalStack] = useState<ModalVariant[]>([]);
  const [isOpen, setIsOpen] = useState(false);
  const smQueryMatches = useMediaQuery(
    `(min-width: ${SMALL_SCREEN_BREAKPOINT})`
  );
  const mode =
    smQueryMatches === null ? null : smQueryMatches ? "dialog" : "drawer";

  const modalInfo = useCurrentModalInfo(modalIdStack);
  const activeDialogWidth = modalStack.at(-1)?.dialogWidth ?? "max-w-sm";

  const show = () => {
    setIsOpen(true);
    return new Promise<void>((res) => {
      setTimeout(() => {
        res();
      }, VISIBILITY_TRANSITION_DURATION);
    });
  };

  const hide = () => {
    setIsOpen(false);
    return new Promise<void>((res) => {
      setTimeout(() => {
        res();
      }, VISIBILITY_TRANSITION_DURATION);
    });
  };

  const onVisibilityChange = (open: boolean) => {
    setIsOpen(open);
  };

  const pushModal = (variant: ModalVariant, replaceAll?: boolean) => {
    setModalIdStack((prev) => [...(replaceAll ? [] : prev), variant.id]);
    setModalStack((prev) => [...(replaceAll ? [] : prev), variant]);
  };

  const popModal = () => {
    setModalIdStack((prev) => prev.slice(0, -1));
    setModalStack((prev) => prev.slice(0, -1));
  };

  const clear = () => {
    setModalIdStack([]);
    setModalStack([]);
  };

  const handleOpenChange = (open: boolean) => {
    setIsOpen(open);
  };
  return (
    <ModalContext.Provider
      value={{
        show,
        hide,
        onVisibilityChange,
        isOpen,
        mode,
        stack: modalIdStack,
        pushModal,
        popModal,
        clear,
      }}
    >
      {children}
      <ModalModeContext.Provider value={mode}>
        <ModalStack
          mode={mode}
          isOpen={isOpen}
          onOpenChange={handleOpenChange}
          dismissible={modalInfo.dismissible}
          dialogWidth={activeDialogWidth}
        >
          <VisuallyHidden.Root>
            {mode === "dialog" ? (
              <DialogHeader>
                <DialogTitle>
                  {typeof modalInfo.title === "string" ? (
                    modalInfo.title
                  ) : (
                    <>{modalInfo.title}</>
                  )}
                </DialogTitle>
                <DialogDescription>
                  {typeof modalInfo.description === "string" ? (
                    modalInfo.description
                  ) : (
                    <>{modalInfo.description}</>
                  )}
                </DialogDescription>
              </DialogHeader>
            ) : mode === "drawer" ? (
              <DrawerHeader>
                <DrawerTitle>
                  {typeof modalInfo.title === "string" ? (
                    modalInfo.title
                  ) : (
                    <>{modalInfo.title}</>
                  )}
                </DrawerTitle>
                <DrawerDescription>
                  {typeof modalInfo.description === "string" ? (
                    modalInfo.description
                  ) : (
                    <>{modalInfo.description}</>
                  )}
                </DrawerDescription>
              </DrawerHeader>
            ) : null}
          </VisuallyHidden.Root>
          {modalStack.map((modal, index) => {
            return (
              <ModalWrapper
                index={index}
                transitionDurationInMs={STACK_UPDATE_TRANSITION_DURATION}
                modal={modal}
                isActive={modalStack.length - 1 === index}
                preventFocusTrap={mode === "drawer"}
                key={modal.id + index}
              />
            );
          })}
        </ModalStack>
      </ModalModeContext.Provider>
    </ModalContext.Provider>
  );
};

export const useModal = () => {
  const context = useContext(ModalContext);
  if (!context) {
    throw new Error("useModal must be used within a ModalProvider");
  }
  return context;
};

