"use client";

import * as React from "react";
import { Drawer as DrawerPrimitive } from "vaul";

import { cn } from "@/lib/utils";

const DRAWER_PADDING_CLASS_PATTERN = /^!?(?:p|px|py|pt|pr|pb|pl|ps|pe)-/;

const splitDrawerClassName = (className?: string) => {
  if (!className) {
    return {
      outerClassName: undefined,
      innerClassName: undefined,
    };
  }

  const outerClasses: string[] = [];
  const innerClasses: string[] = [];

  for (const token of className.trim().split(/\s+/)) {
    const baseToken = token.split(":").at(-1) ?? token;

    if (DRAWER_PADDING_CLASS_PATTERN.test(baseToken)) {
      innerClasses.push(token);
    } else {
      outerClasses.push(token);
    }
  }

  return {
    outerClassName: outerClasses.join(" ") || undefined,
    innerClassName: innerClasses.join(" ") || undefined,
  };
};

function Drawer({
  ...props
}: React.ComponentProps<typeof DrawerPrimitive.Root>) {
  return <DrawerPrimitive.Root data-slot="drawer" {...props} />;
}

function DrawerTrigger({
  ...props
}: React.ComponentProps<typeof DrawerPrimitive.Trigger>) {
  return <DrawerPrimitive.Trigger data-slot="drawer-trigger" {...props} />;
}

function DrawerPortal({
  ...props
}: React.ComponentProps<typeof DrawerPrimitive.Portal>) {
  return <DrawerPrimitive.Portal data-slot="drawer-portal" {...props} />;
}

function DrawerClose({
  ...props
}: React.ComponentProps<typeof DrawerPrimitive.Close>) {
  return <DrawerPrimitive.Close data-slot="drawer-close" {...props} />;
}

function DrawerHandle({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="drawer-handle"
      className={cn(
        "bg-muted mx-auto mt-4 mb-1 h-2 w-[100px] shrink-0 rounded-full",
        className,
      )}
      {...props}
    />
  );
}

function DrawerOverlay({
  className,
  ...props
}: React.ComponentProps<typeof DrawerPrimitive.Overlay>) {
  return (
    <DrawerPrimitive.Overlay
      data-slot="drawer-overlay"
      className={cn(
        "data-[state=open]:animate-in data-[state=closed]:animate-out duration-300 data-[state=closed]:backdrop-blur-none data-[state=open]:backdrop-blur-lg data-[state=closed]:bg-black/0 data-[state=open]:bg-black/20 fixed inset-0 z-50",
        className,
      )}
      {...props}
    />
  );
}

function DrawerPlaceholder({
  className,
  children,
  dismissible = true,
  ...props
}: React.ComponentProps<typeof DrawerPrimitive.Content> & {
  dismissible?: boolean;
}) {
  const { outerClassName, innerClassName } = splitDrawerClassName(className);

  return (
    <DrawerPortal data-slot="drawer-portal">
      <DrawerOverlay />
      <DrawerPrimitive.Content
        data-slot="drawer-content"
        className={cn(
          "group/drawer-content bg-background fixed z-50 flex h-auto min-h-0 min-w-0 flex-col overflow-hidden",
          "data-[vaul-drawer-direction=top]:inset-x-0 data-[vaul-drawer-direction=top]:top-0 data-[vaul-drawer-direction=top]:mb-24 data-[vaul-drawer-direction=top]:max-h-[80dvh] data-[vaul-drawer-direction=top]:rounded-b-3xl data-[vaul-drawer-direction=top]:border-b",
          "data-[vaul-drawer-direction=bottom]:inset-x-0 data-[vaul-drawer-direction=bottom]:bottom-0 data-[vaul-drawer-direction=bottom] data-[vaul-drawer-direction=bottom]:max-h-[80dvh] data-[vaul-drawer-direction=bottom]:rounded-t-3xl data-[vaul-drawer-direction=bottom]:border-t",
          "data-[vaul-drawer-direction=right]:inset-y-0 data-[vaul-drawer-direction=right]:right-0 data-[vaul-drawer-direction=right]:w-3/4 data-[vaul-drawer-direction=right]:border-l data-[vaul-drawer-direction=right]:sm:max-w-sm",
          "data-[vaul-drawer-direction=left]:inset-y-0 data-[vaul-drawer-direction=left]:left-0 data-[vaul-drawer-direction=left]:w-3/4 data-[vaul-drawer-direction=left]:border-r data-[vaul-drawer-direction=left]:sm:max-w-sm",
          outerClassName,
        )}
        {...props}
      >
        {dismissible ? <DrawerHandle /> : null}
        <div
          data-slot="drawer-scroll-body"
          data-vaul-no-drag=""
          className={cn(
            "relative flex min-h-0 min-w-0 flex-1 flex-col overflow-x-hidden overflow-y-auto overscroll-contain p-4",
            innerClassName,
          )}
        >
          {children}
        </div>
      </DrawerPrimitive.Content>
    </DrawerPortal>
  );
}

function DrawerHeader({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="drawer-header"
      className={cn(
        "flex flex-col gap-0.5 p-4 group-data-[vaul-drawer-direction=bottom]/drawer-content:text-center group-data-[vaul-drawer-direction=top]/drawer-content:text-center md:gap-1.5 md:text-left",
        className,
      )}
      {...props}
    />
  );
}

function DrawerFooter({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="drawer-footer"
      className={cn("mt-2 flex flex-col gap-2", className)}
      {...props}
    />
  );
}

function DrawerTitle({
  className,
  ...props
}: React.ComponentProps<typeof DrawerPrimitive.Title>) {
  return (
    <DrawerPrimitive.Title
      data-slot="drawer-title"
      className={cn("text-foreground font-semibold", className)}
      {...props}
    />
  );
}

function DrawerDescription({
  className,
  ...props
}: React.ComponentProps<typeof DrawerPrimitive.Description>) {
  return (
    <DrawerPrimitive.Description
      data-slot="drawer-description"
      className={cn("text-muted-foreground text-sm", className)}
      {...props}
    />
  );
}

export {
  Drawer,
  DrawerPortal,
  DrawerOverlay,
  DrawerTrigger,
  DrawerClose,
  DrawerHandle,
  DrawerPlaceholder,
  DrawerHeader,
  DrawerFooter,
  DrawerTitle,
  DrawerDescription,
};

"use client";

import React, { useContext } from "react";
import { DialogClose, DialogFooter } from "./dialog";
import { DrawerFooter } from "./drawer";
import { ModalModeContext } from "./context";
import { ChevronLeftIcon, XIcon } from "lucide-react";
import { cn } from "@/lib/utils";
import { Button } from "../button";

type ModalDivProps = React.ComponentProps<"div">;

export const ModalHeader = ({
  backAction,
  ...props
}: ModalDivProps & {
  backAction?: () => void;
}) => {
  return (
    <div
      {...(backAction ? {} : props)}
      className={cn(
        "mb-2",
        backAction ? "flex items-center gap-3" : "",
        backAction ? props.className : "",
      )}
    >
      {backAction ? (
        <>
          <Button
            variant={"secondary"}
            size={"icon"}
            className="p-0 h-6 w-6"
            type="button"
            aria-label="Go back"
            onClick={() => {
              backAction();
            }}
          >
            <ChevronLeftIcon />
          </Button>
          <div {...props} />
        </>
      ) : (
        props.children
      )}
    </div>
  );
};

export const ModalTitle = ({ ...props }: ModalDivProps) => {
  return (
    <h1
      {...props}
      className={cn("font-instrument italic text-2xl", props.className)}
      data-modal-title
    />
  );
};

export const ModalDescription = ({ ...props }: ModalDivProps) => {
  return (
    <p
      {...props}
      className={cn("text-sm text-muted-foreground", props.className)}
      data-modal-description
    />
  );
};

export const ModalFooter = ({ ...props }: ModalDivProps) => {
  const mode = useContext(ModalModeContext);
  if (mode === "dialog") {
    return <DialogFooter {...props} />;
  }
  return <DrawerFooter {...props} />;
};

export const ModalContent = ({
  dismissible = true,
  ...props
}: ModalDivProps & {
  dismissible?: boolean;
}) => {
  const mode = useContext(ModalModeContext);
  if (mode === "drawer") {
    return (
      <div data-modal-dismissible={dismissible ? "true" : "false"} {...props} />
    );
  }
  return (
    <>
      {dismissible && (
        <DialogClose className="ring-offset-background focus:ring-ring bg-secondary data-[state=open]:text-muted-foreground absolute top-0 right-0 rounded-full p-1 opacity-100 transition-all hover:brightness-95 dark:hover:brightness-105 focus:ring-2 focus:ring-offset-2 focus:outline-hidden disabled:pointer-events-none [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4">
          <XIcon />
          <span className="sr-only">Close</span>
        </DialogClose>
      )}
      <div data-modal-dismissible={dismissible ? "true" : "false"} {...props} />
    </>
  );
};

import { useEffect, useState } from "react";

type ModalInfo = {
  dismissible: boolean;
  title: Element | string;
  description: Element | string;
};

const DEFAULT_MODAL_INFO: ModalInfo = {
  dismissible: true,
  title: "Untitled Modal",
  description: "No description found for this modal.",
};

const readCurrentModalInfo = (): ModalInfo => {
  const currentModal = document.querySelector("[data-current-modal]");

  if (!currentModal) {
    return DEFAULT_MODAL_INFO;
  }

  const title = currentModal.querySelector("[data-modal-title]");
  const description = currentModal.querySelector("[data-modal-description]");
  const dismissible = currentModal.querySelector("[data-modal-dismissible]");

  return {
    dismissible: dismissible?.getAttribute("data-modal-dismissible") !== "false",
    title: title?.textContent ?? DEFAULT_MODAL_INFO.title,
    description: description?.textContent ?? DEFAULT_MODAL_INFO.description,
  };
};

const areModalInfosEqual = (left: ModalInfo, right: ModalInfo) => {
  return (
    left.dismissible === right.dismissible &&
    left.title === right.title &&
    left.description === right.description
  );
};

const useCurrentModalInfo = (modalIdStack: string[]) => {
  const [modalInfo, setModalInfo] = useState<ModalInfo>(DEFAULT_MODAL_INFO);

  useEffect(() => {
    let timeoutId: ReturnType<typeof setTimeout> | null = null;

    const syncModalInfo = () => {
      const nextModalInfo = readCurrentModalInfo();

      setModalInfo((currentModalInfo) => {
        return areModalInfosEqual(currentModalInfo, nextModalInfo)
          ? currentModalInfo
          : nextModalInfo;
      });
    };

    syncModalInfo();
    timeoutId = setTimeout(syncModalInfo, 100);

    return () => {
      if (timeoutId !== null) {
        clearTimeout(timeoutId);
      }
    };
  }, [modalIdStack]);

  return modalInfo;
};

export default useCurrentModalInfo;

import { useState, useEffect } from "react";

const useMediaQuery = (query: string): boolean => {
  // Initialize with null during SSR to avoid hydration mismatch
  const [matches, setMatches] = useState<boolean>(true);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    // Use setTimeout to avoid synchronous setState in effect
    setTimeout(() => {
      setMounted(true);
    }, 0);

    // Only run on client-side
    if (typeof window !== "undefined") {
      const mediaQuery = window.matchMedia(query);

      // Set initial value - use setTimeout to avoid synchronous setState
      setTimeout(() => {
        setMatches(mediaQuery.matches);
      }, 0);

      // Create event listener function
      const handler = (event: MediaQueryListEvent) => {
        setMatches(event.matches);
      };

      // Add event listener
      mediaQuery.addEventListener("change", handler);

      // Cleanup
      return () => {
        mediaQuery.removeEventListener("change", handler);
      };
    }
  }, [query]);

  // Return false during SSR, actual value after mounting
  return mounted ? matches : false;
};

export default useMediaQuery;
